import { supabase } from "../client";

export const getEvidencias = async () => {


    let { data: Evidencias, error } = await supabase
        .from('Evidencias')
        .select('*');


    return Evidencias;

}


export const getEvidenciaById = async (id) => {  
    let { data: Evidencia, error } = await supabase
    .from('Evidencias')
    .select("*")
    .eq('id', id);
    return Evidencia;
}
